<?php
namespace App\Domain\Hunts\Playback;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\Data\CombatAction;use InvalidArgumentException;
final class HuntingPlaybackCalculator{public function calculate(array $actions,$status,$multiplier){if(!is_int($multiplier)||$multiplier<=0)throw new InvalidArgumentException('Invalid playback multiplier.');$events=[];$offset=0;foreach($actions as $action){if(!$action instanceof CombatAction)throw new InvalidArgumentException('Invalid playback action.');$base=HuntingPlaybackLimits::BASE_ATTACK_DELAY_MS+($action->critical()?HuntingPlaybackLimits::CRITICAL_EXTRA_DELAY_MS:0)+($action->defenderHealthBefore()>0&&$action->defenderHealthAfter()===0?HuntingPlaybackLimits::TARGET_DEFEATED_EXTRA_DELAY_MS:0);$duration=$this->scaled($base,$multiplier);if($duration>HuntingPlaybackLimits::MAX_PLAYBACK_DURATION_MS-$offset)throw new InvalidArgumentException('Playback duration exceeds operational limit.');$events[]=['action'=>$action,'playback_offset_ms'=>$offset,'playback_duration_ms'=>$duration];$offset+=$duration;}$result=$this->scaled(HuntingPlaybackLimits::RESULT_REVEAL_DELAY_MS,$multiplier);$loot=$status===CombatResultStatus::CHARACTER_VICTORY?$this->scaled(HuntingPlaybackLimits::LOOT_REVEAL_DELAY_MS,$multiplier):0;if($result>HuntingPlaybackLimits::MAX_PLAYBACK_DURATION_MS-$offset||$loot>HuntingPlaybackLimits::MAX_PLAYBACK_DURATION_MS-$offset-$result)throw new InvalidArgumentException('Playback duration exceeds operational limit.');return new HuntingPlaybackResult($events,$offset,$result,$loot,$offset+$result+$loot,$multiplier);}public function millisecondsToCeilingSeconds($milliseconds){if(!is_int($milliseconds)||$milliseconds<0)throw new InvalidArgumentException('Invalid milliseconds.');return intdiv($milliseconds,1000)+($milliseconds%1000===0?0:1);}private function scaled($base,$multiplier){if($base>intdiv(PHP_INT_MAX,10000))throw new InvalidArgumentException('Playback duration overflow.');$numerator=$base*10000;$value=intdiv($numerator,$multiplier)+($numerator%$multiplier===0?0:1);return max(HuntingPlaybackLimits::MIN_SEGMENT_DELAY_MS,$value);}}
